int evaluatePostfix(string expr) {
    stack<int> s;
    for (char c : expr) {
        if (c >= '0' && c <= '9') {
            s.push(c - '0');
        } else if (c == '+' || c == '-' || c == '*' || c == '/') {
            if (s.size() < 2) {
                throw runtime_error("Invalid expression");
            }
            int b = s.top();
            s.pop();
            int a = s.top();
            s.pop();
            switch (c) {
                case '+': s.push(a + b); break;
                case '-': s.push(a - b); break;
                case '*': s.push(a * b); break;
                case '/': s.push(a / b); break;
            }
        } else {
            throw runtime_error("Invalid symbol");
        }
    }
    if (s.size() != 1) {
        throw runtime_error("Invalid expression");
    }
    return s.top();
}

int main() {
    try {
        string expr = "3 4 + 5 *";
        cout << "Result: " << evaluatePostfix(expr) << endl;
    } catch (const runtime_error& e) {
        cout << "Error: " << e.what() << endl;
    }
    return 0;
}

