type UserRequest struct {
	UserID string
}

type Queue struct {
	queue []UserRequest
}

func (q *Queue) PushBack(userID string) {
	q.queue = append(q.queue, UserRequest{UserID: userID})
}

func (q *Queue) PushFront(userID string) {
	q.queue = append([]UserRequest{UserRequest{UserID: userID}}, q.queue...)
}

func (q *Queue) Peek() (UserRequest, bool) {
	if len(q.queue) == 0 {
		return UserRequest{}, false
	}
	return q.queue[0], true
}

func (q *Queue) Dequeue() (UserRequest, bool) {
	if len(q.queue) == 0 {
		return UserRequest{}, false
	}
	result := q.queue[0]
	q.queue = q.queue[1:]
	return result, true
}

func (q *Queue) Size() int {
	return len(q.queue)
}

func (q *Queue) IsEmpty() bool {
	return len(q.queue) == 0
}

func main() {
	queue := &Queue{}
	queue.PushBack("user123")
	queue.PushFront("user456")
	fmt.Println("Queue after pushback and pushfront:", queue.queue)

	for i := 0; i < 5; i++ {
		user, ok := queue.Peek()
		if ok {
			fmt.Printf("Peek: %s\n", user.UserID)
			queue.Dequeue()
