public class MaxSumNonConsecutive {
    public static int maxSumNonConsecutive(int[] nums) {
        HashMap<Integer, Integer> cache = new HashMap<>();
        return helper(nums, 0, 0, cache);
    }

    private static int helper(int[] nums, int index, int sum, HashMap<Integer, Integer> cache) {
        if (index >= nums.length) {
            return sum;
        }
        int key = index + sum;
        if (cache.containsKey(key)) {
            return cache.get(key);
        }
        int include = nums[index] + helper(nums, index + 1, sum, cache);
        int exclude = helper(nums, index + 1, sum, cache);
        int maxSum = Math.max(include, exclude);
        cache.put(key, maxSum);
