import java.util.*;

public class SocialNetwork {
    private HashMap<String, List<String>> followEvents = new HashMap<>();
    private HashMap<String, Set<String>> followers = new HashMap<>();
    private HashMap<String, Set<String>> mutualFollowers = new HashMap<>();

    public void follow(String follower, String followed) {
        if (!followEvents.containsKey(follower)) {
            followEvents.put(follower, new ArrayList<>());
        }
        followEvents.get(follower).add(followed);

        if (!followers.containsKey(follower)) {
            followers.put(follower, new HashSet<>());
        }
        followers.get(follower).add(followed);

        if (!mutualFollowers.containsKey(follower)) {
            mutualFollowers.put(follower, new HashSet<>());
        }
        mutualFollowers.get(follower).add(followed);
    }

    public Set<String> getMutualFollowers(String user1, String user2) {
        if (!followers.containsKey(user1) || !followers.containsKey(user2)) {
            return new HashSet<>();
        }
        Set<String> mutual = new HashSet<>();
        for (String follower : followers.get(user1)) {
            if (followers.get(user2).contains(follower)) {
                mutual.add(follower);
            }
        }
        return mutual;
    }

    public void recordFollowEvent(String follower, String followed) {
        followEvents.getOrDefault(follower, new ArrayList<>()).add(followed);
    }

    public List<String> getFollowEvents(String user) {
        return followEvents.getOrDefault(user, new ArrayList<>());
    }
